from dataclasses import dataclass
from typing import Optional


@dataclass
class ScepticismConcern:
    stakeholder: str
    concern: str
    category: str    # "accuracy", "accountability", "scope", "data_quality"
    evidence_needed: str
    response_owner: str
    resolved: bool = False
    resolution_evidence: str = ""

    def needs_escalation(self) -> bool:
        """Escalate if unresolved after two evidence-response cycles."""
        return not self.resolved and bool(self.resolution_evidence)


@dataclass
class ResistanceLog:
    initiative_id: str
    concerns: list[ScepticismConcern]

    def open_concerns(self) -> list[ScepticismConcern]:
        return [c for c in self.concerns if not c.resolved]

    def by_category(self) -> dict[str, list[ScepticismConcern]]:
        result: dict[str, list[ScepticismConcern]] = {}
        for c in self.concerns:
            result.setdefault(c.category, []).append(c)
        return result

    def summary(self) -> str:
        cats = self.by_category()
        lines = [f"Resistance log: {len(self.open_concerns())}/{len(self.concerns)} open"]
        for cat, items in cats.items():
            open_count = sum(1 for c in items if not c.resolved)
            lines.append(f"  {cat}: {open_count}/{len(items)} open")
        return "\n".join(lines)


log = ResistanceLog(
    initiative_id="legal-summariser",
    concerns=[
        ScepticismConcern(
            stakeholder="Senior Legal Analyst",
            concern="ROUGE-L 0.43 on test set does not mean it is accurate on novel contract types",
            category="accuracy",
            evidence_needed="Domain-specific eval on M&A contract subset with legal SME review",
            response_owner="ML Lead",
            resolved=False,
        ),
        ScepticismConcern(
            stakeholder="Legal Team Lead",
            concern="Who is accountable when a client acts on an AI-summarised clause that was wrong?",
            category="accountability",
            evidence_needed="Written accountability policy signed by Legal Director",
            response_owner="General Counsel + Programme Manager",
            resolved=True,
            resolution_evidence="Accountability policy v1.2 signed 2026-06-15; human review checkpoint mandatory",
        ),
    ],
)
print(log.summary())
for c in log.open_concerns():
    print(f"  OPEN [{c.category}] {c.stakeholder}: {c.concern[:60]}...")
    print(f"    Evidence needed: {c.evidence_needed}")

from dataclasses import dataclass
from enum import Enum


class OppositionRoot(Enum):
    UNADDRESSED_SCEPTICISM = "unaddressed_scepticism"
    TERRITORIAL = "territorial"          # role authority or status threat
    IDEOLOGICAL = "ideological"          # principled objection to AI in general
    PERSONAL_HISTORY = "personal_history"  # negative prior experience with AI tools


@dataclass
class ActiveOppositionCase:
    person_id: str
    influence_scope: str    # who they are influencing
    opposition_root: OppositionRoot
    observable_behaviours: list[str]

    def response_strategy(self) -> str:
        if self.opposition_root == OppositionRoot.UNADDRESSED_SCEPTICISM:
            return (
                "Prioritise concern resolution first. Assign a senior technical stakeholder "
                "to meet 1:1 and address each specific concern with evidence. Escalate only "
                "if concerns cannot be substantively resolved."
            )
        if self.opposition_root == OppositionRoot.TERRITORIAL:
            return (
                "Executive sponsor delivers a direct message that adoption is expected. "
                "Offer the person a visible role in the adoption (e.g., co-facilitating "
                "a team workshop) to redirect status energy toward the change rather than against it."
            )
        if self.opposition_root == OppositionRoot.IDEOLOGICAL:
            return (
                "Acknowledge the principled position; set clear expectation that the "
                "organisational decision is made. Focus on behaviours required: "
                "the person need not endorse AI but must not actively undermine adoption."
            )
        return (
            "Understand prior AI experience; ensure this tool addresses the specific "
            "failure mode they encountered. If it does not, acknowledge the gap honestly."
        )


case = ActiveOppositionCase(
    person_id="TL-Engineering-B",
    influence_scope="12-person engineering team",
    opposition_root=OppositionRoot.TERRITORIAL,
    observable_behaviours=[
        "Telling team members code reviews must be 'done properly' without AI",
        "Declining to attend AI adoption workshops",
        "Publicly questioning the ROI in all-hands Q&A",
    ],
)
print(f"Active Opposition Case: {case.person_id}")
print(f"Root: {case.opposition_root.value}")
print(f"Strategy: {case.response_strategy()}")

from dataclasses import dataclass, field
from collections import Counter


@dataclass
class ResistanceSignal:
    employee_id: str
    team: str
    function: str
    concern_text: str
    type_: str  # "scepticism", "anxiety", "opposition"
    week_detected: int


@dataclass
class ResistanceAnalytics:
    signals: list[ResistanceSignal] = field(default_factory=list)

    def add(self, signal: ResistanceSignal) -> None:
        self.signals.append(signal)

    def by_team(self) -> dict[str, int]:
        counts: Counter = Counter()
        for s in self.signals:
            counts[s.team] += 1
        return dict(counts.most_common())

    def by_function(self) -> dict[str, int]:
        counts: Counter = Counter()
        for s in self.signals:
            counts[s.function] += 1
        return dict(counts.most_common())

    def cluster_alert(self, threshold_pct: float = 0.40) -> list[str]:
        """Return teams where resistance rate exceeds threshold of all signals."""
        total = len(self.signals)
        if total == 0:
            return []
        alerts = []
        for team, count in self.by_team().items():
            if count / total >= threshold_pct:
                alerts.append(f"Team '{team}' accounts for {count/total*100:.0f}% of resistance signals")
        return alerts

    def repeated_concerns(self, min_count: int = 3) -> list[tuple[str, int]]:
        """Return concern phrases appearing >= min_count times (simplified keyword match)."""
        keywords = ["accountability", "accuracy", "job", "liability", "data", "trust"]
        counts: Counter = Counter()
        for s in self.signals:
            for kw in keywords:
                if kw in s.concern_text.lower():
                    counts[kw] += 1
        return [(kw, count) for kw, count in counts.most_common() if count >= min_count]


analytics = ResistanceAnalytics()
sample_signals = [
    ("EMP-001", "Legal-A", "Legal", "Who is accountable for wrong summaries?", "scepticism", 2),
    ("EMP-002", "Legal-A", "Legal", "Accuracy on M&A documents is not proven", "scepticism", 2),
    ("EMP-003", "Legal-A", "Legal", "Job scope feels unclear after AI introduction", "anxiety", 3),
    ("EMP-004", "Legal-B", "Legal", "Liability when client acts on AI output", "scepticism", 2),
    ("EMP-005", "Legal-B", "Legal", "Accountability policy not clear enough", "scepticism", 3),
    ("EMP-006", "Engineering", "Tech", "Trust in AI code review quality", "scepticism", 2),
]
for args in sample_signals:
    analytics.add(ResistanceSignal(*args))

print("Resistance analytics:")
print(f"  By team: {analytics.by_team()}")
alerts = analytics.cluster_alert(threshold_pct=0.30)
for a in alerts:
    print(f"  CLUSTER: {a}")
repeated = analytics.repeated_concerns(min_count=2)
print(f"  Repeated concern keywords: {repeated}")
print("  → 'accountability' appearing 3x is a systemic gap requiring a published policy")
